func (p *Provider) getConfiguration(instance ecsInstance) (configuration, error) {
	conf := configuration{
		Enable: p.ExposedByDefault,
	}

	err := label.Decode(instance.Labels, &conf, "traefik.ecs.", "traefik.enable")
	if err != nil {
		return configuration{}, err
	}

	return conf, nil
}
